[{"name_path": "toStorageVaultStore", "kind": "Function", "relative_path": "internal/daemon/controller/handlers/credentialstores/credentialstore_service.go", "body_location": {"start_line": 714, "end_line": 768}, "body": "func toStorageVaultStore(scopeId string, in *pb.CredentialStore) (out *vault.CredentialStore, err error) {
	const op = "credentialstores.toStorageVaultStore"
	var opts []vault.Option
	if in.GetName() != nil {
		opts = append(opts, vault.WithName(in.GetName().GetValue()))
	}
	if in.GetDescription() != nil {
		opts = append(opts, vault.WithDescription(in.GetDescription().GetValue()))
	}

	attrs := in.GetVaultCredentialStoreAttributes()
	if attrs.GetTlsServerName() != nil {
		opts = append(opts, vault.WithTlsServerName(attrs.GetTlsServerName().GetValue()))
	}
	if attrs.GetTlsSkipVerify().GetValue() {
		opts = append(opts, vault.WithTlsSkipVerify(attrs.GetTlsSkipVerify().GetValue()))
	}
	if attrs.GetNamespace().GetValue() != "" {
		opts = append(opts, vault.WithNamespace(attrs.GetNamespace().GetValue()))
	}
	if attrs.GetWorkerFilter().GetValue() != "" {
		opts = append(opts, vault.WithWorkerFilter(attrs.GetWorkerFilter().GetValue()))
	}

	// TODO (ICU-1478 and ICU-1479): Update the vault's interface around ca cert to match oidc's,
	//  accepting x509.Certificate instead of []byte
	if attrs.GetCaCert() != nil {
		opts = append(opts, vault.WithCACert([]byte(attrs.GetCaCert().GetValue())))
	}
	pemCerts, pemPk, err := extractClientCertAndPk(attrs.GetClientCertificate().GetValue(), attrs.GetClientCertificateKey().GetValue())
	if err != nil {
		return nil, errors.WrapDeprecated(err, op)
	}
	if len(pemCerts) != 0 {
		var cert []byte
		for _, c := range pemCerts {
			cert = append(cert, pem.EncodeToMemory(c)...)
		}
		var pk []byte
		if pemPk != nil {
			pk = pem.EncodeToMemory(pemPk)
		}
		cc, err := vault.NewClientCertificate(cert, pk)
		if err != nil {
			return nil, errors.WrapDeprecated(err, op)
		}
		opts = append(opts, vault.WithClientCert(cc))
	}

	cs, err := vault.NewCredentialStore(scopeId, attrs.GetAddress().GetValue(), []byte(attrs.GetToken().GetValue()), opts...)
	if err != nil {
		return nil, errors.WrapDeprecated(err, op, errors.WithMsg("unable to build credential store for creation"))
	}
	return cs, err
}"}]

[{"name_path": "extractClientCertAndPk", "kind": "Function", "relative_path": "internal/daemon/controller/handlers/credentialstores/vault.go", "body_location": {"start_line": 14, "end_line": 50}, "body": "func extractClientCertAndPk(cert, pk string) ([]*pem.Block, *pem.Block, error) {
	const op = "credentialstores.extractClientCertAndPk"
	pks, err := decodePemBlocks(pk)
	if err != nil {
		return nil, nil, errors.WrapDeprecated(err, op, errors.WithMsg("failed to parse client certificate private key"))
	}
	var pkPem *pem.Block
	switch len(pks) {
	case 0:
	case 1:
		pkPem = pks[0]
	default:
		return nil, nil, errors.NewDeprecated(errors.InvalidParameter, op, "private key payload contained multiple pem blocks")
	}

	bs, err := decodePemBlocks(cert)
	if err != nil {
		return nil, nil, errors.WrapDeprecated(err, op, errors.WithMsg("failed to parse client certificate into pem blocks"))
	}
	pkIdx := -1
	for i, b := range bs {
		if !strings.Contains(b.Type, "CERTIFICATE") {
			switch {
			case pkPem == nil:
				pkIdx, pkPem = i, b
			case pkIdx < 0:
				return nil, nil, errors.NewDeprecated(errors.InvalidParameter, op, "client certificate contains a private key when one was also provided separately")
			default:
				return nil, nil, errors.NewDeprecated(errors.InvalidParameter, op, fmt.Sprintf("second primary key found at %d after previous one found at %d", i, pkIdx))
			}
		}
	}
	if pkIdx >= 0 {
		bs = append(bs[:pkIdx], bs[pkIdx+1:]...)
	}
	return bs, pkPem, nil
}"}]

[{"name_path": "decodePemBlocks", "kind": "Function", "relative_path": "internal/daemon/controller/handlers/credentialstores/vault.go", "body_location": {"start_line": 52, "end_line": 69}, "body": "func decodePemBlocks(input string) ([]*pem.Block, error) {
	const op = "credentialstores.decodePemBlocks"
	cpIn := make([]byte, len(input))
	copy(cpIn, input)
	var p *pem.Block
	var ret []*pem.Block
	for {
		p, cpIn = pem.Decode(cpIn)
		if p == nil {
			break
		}
		ret = append(ret, p)
	}
	if len(cpIn) > 0 {
		return nil, errors.NewDeprecated(errors.InvalidParameter, op, "not all data parseable by pem block")
	}
	return ret, nil
}"}]

