							badFields[attrFilterField] = fmt.Sprintf("Error evaluating submitted filter expression: %v.", err)
						}
					}
				}
			}
		default:
			badFields[globals.IdField] = "Unrecognized resource type."
		}
		return badFields
	}, intglobals.OidcManagedGroupPrefix)
}"}, {"name_path": "validateUpdateRequest", "kind": "Function", "relative_path": "internal/daemon/controller/handlers/roles/role_service.go", "body_location": {"start_line": 913, "end_line": 935}, "body": "func validateUpdateRequest(req *pbs.UpdateRoleRequest) error {
